<!-- wp:pullquote {"style":{"spacing":{"padding":{"top":"var:preset|spacing|70","bottom":"var:preset|spacing|70"}}}} -->
<figure class="wp-block-pullquote" style="padding-top:var(--wp--preset--spacing--70);padding-bottom:var(--wp--preset--spacing--70)"><blockquote><p>Black fly larvae attach to leaves and other substrates via a silkened pad and a circle of hooks at the base of their body, similar to Velcro.</p></blockquote></figure>
<!-- /wp:pullquote -->

<!-- wp:caes-hub/caes-gallery {"rows":[{"columns":3,"images":[{"id":92268,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4810.jpg","alt":"Larvae clinging to a leaf under flowing water.","caption":"Black fly larvae cling to the surface of a leaf.","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4810-150x150.jpg","orientation":"landscape"},"medium":{"height":207,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4810-300x207.jpg","orientation":"landscape"},"large":{"height":705,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4810-1024x705.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4810.jpg","height":1388,"width":2016,"orientation":"landscape"}}},{"id":92430,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4722-scaled.jpg","alt":"Hands holding a leaf with larvae on its surface.","caption":"A closer view of black fly larvae clinging to the surface of a leaf.","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4722-150x150.jpg","orientation":"landscape"},"medium":{"height":200,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4722-300x200.jpg","orientation":"landscape"},"large":{"height":683,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4722-1024x683.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4722-scaled.jpg","height":1707,"width":2560,"orientation":"landscape"}}},{"id":92301,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4815.jpg","alt":"A close-up of larvae on the surface of a leaf.","caption":"Black fly larvae get their close-up on the surface of a leaf.","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4815-150x150.jpg","orientation":"landscape"},"medium":{"height":300,"width":217,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4815-217x300.jpg","orientation":"portrait"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4815.jpg","height":969,"width":700,"orientation":"portrait"}}}]}],"align":"wide","style":{"spacing":{"padding":{"top":"0","bottom":"0"},"margin":{"top":"0","bottom":"0"}}}} /-->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"var:preset|spacing|60","bottom":"0"}}}} -->
<p style="padding-top:var(--wp--preset--spacing--60);padding-bottom:0">Black flies — <em>Simulium vittatum</em> — require flowing water to complete their life cycle, and the colony simulates this environment with nine aquatic rearing units that create miniature rivers for the larval and pupal stages to develop. </p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"0","bottom":"0"}}}} -->
<p style="padding-top:0;padding-bottom:0">Each unit can support approximately 300,000 larvae. Adult flies emerge within the rearing units and are captured, mated and provided moistened substrates to serve as egg-laying sites. At any given time there are more than 2 million of the tiny insects at the colony's lab on Riverbend Road.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"bottom":"var:preset|spacing|70"}}}} -->
<p style="padding-bottom:var(--wp--preset--spacing--70)">Black flies are one of the world's most noxious pests, considered the third-most important arthropod vector and pest after mosquitoes and ticks due to their aggressive biting behavior. Black flies transmit the nematode that causes <a href="https://www.cdc.gov/dpdx/onchocerciasis/index.html#:~:text=Microscopy,Parasite%20Biology">onchocerciasis</a>, also known as river blindness, the second-most common cause of blindness due to infection.</p>
<!-- /wp:paragraph -->

<!-- wp:caes-hub/caes-gallery {"rows":[{"columns":1,"images":[{"id":92418,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4360-scaled.jpg","alt":"A view of the Chattahoochee River","caption":"To evaluate the carry of the larvicide downstream, researchers identified a portion of the Chattahoochee River with uniform river flow.","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4360-150x150.jpg","orientation":"landscape"},"medium":{"height":200,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4360-300x200.jpg","orientation":"landscape"},"large":{"height":683,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4360-1024x683.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4360-scaled.jpg","height":1707,"width":2560,"orientation":"landscape"}}}]}],"align":"wide","style":{"spacing":{"padding":{"top":"0","bottom":"0"},"margin":{"top":"0","bottom":"0"}}}} /-->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"0","bottom":"0"}}}} -->
<p style="padding-top:0;padding-bottom:0">Recently, <a href="https://extension.uga.edu/about/personnel-directory/person.html/5961/elmer-gray.html">Elmer Gray</a>, UGA Cooperative Extension entomologist and director of the <a href="https://site.caes.uga.edu/blackflylab/">Black Fly Lab</a>, led a team conducting field studies for Valent BioSciences to test the effectiveness of <em>Vectobac 12AS</em>, a naturally derived larvicide that uses <em>Bacillus thuringiensis</em> subsp. <em>israelensis</em> (Bti) to control black fly populations. </p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"0","bottom":"0"}}}} -->
<p style="padding-top:0;padding-bottom:0">Each day, researchers measured the flow of the river — including its width, depth and speed — to determine how much water was moving through when treatments were applied.</p>
<!-- /wp:paragraph -->

<!-- wp:caes-hub/caes-gallery {"rows":[{"columns":3,"images":[{"id":92419,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4373-scaled.jpg","alt":"A person wades through the river trailing a measuring tape.","caption":"Elmer Gray measures the width of the Chattahoochee River to determine the cubic meters of flow.","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4373-150x150.jpg","orientation":"landscape"},"medium":{"height":197,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4373-300x197.jpg","orientation":"landscape"},"large":{"height":673,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4373-1024x673.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4373-scaled.jpg","height":1681,"width":2560,"orientation":"landscape"}}},{"id":92420,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4416-scaled.jpg","alt":"A close-up of a person holding a stopwatch.","caption":"Elmer Gray times a floating cork over 10 meters to determine the flow of the river. ","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4416-150x150.jpg","orientation":"landscape"},"medium":{"height":199,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4416-300x199.jpg","orientation":"landscape"},"large":{"height":680,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4416-1024x680.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4416-scaled.jpg","height":1699,"width":2560,"orientation":"landscape"}}},{"id":92417,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4351-scaled.jpg","alt":"A person measures the height of the river with a yard stick.","caption":"Elmer Gray measures the depth of the river. ","sizes":{"thumbnail":{"height":150,"width":150,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4351-150x150.jpg","orientation":"landscape"},"medium":{"height":193,"width":300,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4351-300x193.jpg","orientation":"landscape"},"large":{"height":659,"width":1024,"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4351-1024x659.jpg","orientation":"landscape"},"full":{"url":"http://stg-caeshub-staging.kinsta.cloud/wp-content/uploads/2025/11/CAES-BlackFlyResearch-102325-SeanMontgomery-4351-scaled.jpg","height":1647,"width":2560,"orientation":"landscape"}}}]}],"showCaptions":true,"align":"full","style":{"spacing":{"padding":{"right":"0","left":"0"},"margin":{"right":"0","left":"0"}}}} /-->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"0","bottom":"0"}}}} -->
<p style="padding-top:0;padding-bottom:0">After applying the larvicide at a set rate, researchers allowed the treated water to travel downstream for two hours before collecting black fly larvae samples. The larvae were then carefully transported back to the lab, kept cool and supplied with oxygen, and checked for survival 24 hours later. </p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"style":{"spacing":{"padding":{"top":"0","bottom":"0"}}}} -->
<p style="padding-top:0;padding-bottom:0">The goal of the research is to help ensure that the larvicide continues to be a safe and effective tool for controlling black flies.</p>
<!-- /wp:paragraph -->

